parameters.functionCode:
// Получаем данные из вебхука
const item = $input.first().json;
const email = item.email;
const answers = item.answers;

// Эталонные ответы (в реальности берутся из базы)
const correctAnswers = {
  q1: 'создать сделку',
  q2: 'прикрепить файл',
  q3: 'назначить ответственного'
};

// Анализируем результаты
const mistakes = [];
let correctCount = 0;

for (const [question, answer] of Object.entries(answers)) {
  if (answer === correctAnswers[question]) {
    correctCount++;
  } else {
    mistakes.push({
      question,
      correct: correctAnswers[question],
      given: answer
    });
  }
}

const totalQuestions = Object.keys(correctAnswers).length;
const score = (correctCount / totalQuestions) * 100;
const passed = score >= 80; // Проходной балл 80%

// Формируем результат
return {
  email,
  score,
  passed,
  mistakes: mistakes.length > 0 ? mistakes : null,
  timestamp: new Date().toISOString()
};

